mapper.select:
select id, area_id, store_no, store_name, store_address, max_longitude, max_latitude, min_longitude, min_latitude, longitude, latitude, store_introduce, start_time, close_time, store_status, create_time, update_time from store
store_name like concat('%',#{storeName},'%')
and start_time>=#{startTime}
and close_time<=#{closeTime}
order by create_time desc

select id, area_id, store_no, store_name, store_address, max_longitude, max_latitude, min_longitude,
min_latitude, longitude, latitude, store_introduce, start_time, close_time, store_status,
create_time, update_time from store where store_no=#{storeNo}
